  private val allowedSortColumns = Set("name", "price", "category", "brand")
  private val allowedCategories = Set("electronics", "clothing", "books", "home", "sports")
  private val allowedBrands = Set("brand_a", "brand_b", "brand_c", "brand_d")

  def search(): Action[AnyContent] = Action.async { implicit request =>
    val queryParams = request.queryString

    val nameOpt = queryParams.get("name").flatMap(_.headOption).map(sanitizeInput)
    val categoryOpt = queryParams.get("category").flatMap(_.headOption).map(sanitizeInput)
    val brandOpt = queryParams.get("brand").flatMap(_.headOption).map(sanitizeInput)
    val minPriceOpt = queryParams.get("minPrice").flatMap(_.headOption).flatMap(parseDecimal)
    val maxPriceOpt = queryParams.get("maxPrice").flatMap(_.headOption).flatMap(parseDecimal)
    val inStockOpt = queryParams.get("inStock").flatMap(_.headOption).flatMap(parseBoolean)
    val sortBy = queryParams.get("sortBy").flatMap(_.headOption).filter(allowedSortColumns.contains).getOrElse("name")
    val sortOrder = queryParams.get("sortOrder").flatMap(_.headOption).filter(o => o == "asc" || o == "desc").getOrElse("asc")

    if (categoryOpt.exists(c => !allowedCategories.contains(c.toLowerCase))) {
      Future.successful(BadRequest("Invalid category"))
    } else if (brandOpt.exists(b => !allowedBrands.contains(b.toLowerCase))) {
