  private def buildSecureQuery(
    nameOpt: Option[String],
    categoryOpt: Option[String],
    brandOpt: Option[String],
    minPriceOpt: Option[BigDecimal],
    maxPriceOpt: Option[BigDecimal],
    inStockOpt: Option[Boolean],
    sortBy: String,
    sortOrder: String
  ): SqlStreamingAction[Vector[Product], Product, Effect.Read] = {
    
    var conditions = List.empty[SQLActionBuilder]
    
    nameOpt.foreach { name =>
      conditions = conditions :+ sql"name ILIKE ${"%" + name + "%"}"
    }
    
    categoryOpt.foreach { category =>
      conditions = conditions :+ sql"category = $category"
    }
    
    brandOpt.foreach { brand =>
      conditions = conditions :+ sql"brand = $brand"
    }
    
    minPriceOpt.foreach { minPrice =>
      conditions = conditions :+ sql"price >= $minPrice"
    }
    
    maxPriceOpt.foreach { maxPrice =>
      conditions = conditions :+ sql"price <= $maxPrice"
    }
    
    inStockOpt.foreach { inStock =>
      conditions = conditions :+ sql"in_stock = $inStock"
    }

    val whereClause = if (conditions.isEmpty) {
      sql"1=1"
    } else {
      conditions.reduce((a, b) => a ++ sql" AND " ++ b)
    }

    val orderByClause = sortBy match {
      case "name" => if (sortOrder == "asc") sql"name ASC" else sql"name DESC"
      case "price" => if (sortOrder == "asc") sql"price ASC" else sql"price DESC"
      case "category" => if (sortOrder == "asc") sql"category ASC" else sql"category DESC"
      case "brand" => if (sortOrder == "asc") sql"brand ASC" else sql"brand DESC"
      case _ => sql"name ASC"
    }

    val query = sql"SELECT id, name, description, price, category, brand, in_stock FROM products WHERE " ++ whereClause ++ sql" ORDER BY " ++ orderByClause

    query.as[Product]
